const { spawn } = require('child_process');

exports.handler = async (event) => {
  const record = event.Records[0];
  const s3Event = record.s3;
  const imageKey = s3Event.object.key;
  const format = record.requestParameters.format;

  const convertCommand = ['convert', `${imageKey}`, `-format`, format, 'output.jpg'];
  const convertProcess = spawn('convert', convertCommand);

  convertProcess.on('error', (error) => {
    console.error('Image conversion error:', error);
    throw error;
  });

  convertProcess.on('close', (code) => {
    if (code !== 0) {
      console.error(`Image conversion process exited with code ${code}`);
      throw new Error('Image conversion failed');
    }

    // Upload converted image to S3
    // ... S3 upload code here ...

    console.log(`Image converted to ${format}`);
  });
};